package main

import (
	"html/template"
	"net/http"
	"strings"
)

type Comment struct {
	Author  string
	Content string
}

var comments = []Comment{
	{"Alice", "This is a great post!"},
	{"Bob", "I love this! <strong>Bold text</strong>"},
	{"Charlie", "Nice work! <em>Italic text</em>"},
}

func sanitize(input string) string {
	return template.HTMLEscapeString(input)
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := `
	<!DOCTYPE html>
	<html lang="en">
	<head>
		<meta charset="UTF-8">
		<meta name="viewport" content="width=device-width, initial-scale=1.0">
		<title>User Comments</title>
	</head>
	<body>
		<h1>User Comments</h1>
		<ul>
			{{range .}}
				<li><strong>{{.Author}}:</strong> {{.Content | safeHTML}}</li>
			{{end}}
		</ul>
	</body>
	</html>
	`

	funcMap := template.FuncMap{
		"safeHTML": func(content string) template.HTML {
			return template.HTML(content)
		},
	}

	t, err := template.New("comments").Funcs(funcMap).Parse(tmpl)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	for i := range comments {
		comments[i].Content = sanitize(comments[i].Content)
	}

	if err := t.Execute(w, comments); err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}